class BTreeNode {
    int[] keys;
    BTreeNode[] children;
    boolean leaf;
    int n;

    public BTreeNode(boolean leaf) {
        this.keys = new int[3];
        this.children = new BTreeNode[4];
        this.leaf = leaf;
        this.n = 0;
    }
}

class BTree {
    private BTreeNode root;
    private int t;

    public BTree(int t) {
        this.root = new BTreeNode(true);
        this.t = t;
    }

    public void insert(int k) {
        BTreeNode root = this.root;
        if (root.n == 2 * t - 1) {
            BTreeNode newRoot = new BTreeNode(false);
            newRoot.children[0] = this.root;
            newRoot.n = 0;
            splitChild(newRoot, 0);
            this.root = newRoot;
            insertNonFull(newRoot, k);
        } else {
            insertNonFull(root, k);
        }
    }

    private void insertNonFull(BTreeNode node, int k) {
        int i = node.n - 1;
        if (node.leaf) {
            while (i >= 0 && k < node.keys[i]) {
                node.keys[i + 1] = node.keys[i];
                i--;
            }
            node.keys[i + 1] = k;
            node.n++;
        } else {
            while (i >= 0 && k < node.keys[i]) {
                i--;
            }
            i++;
            if (node.children[i].n == 2 * t - 1) {
                splitChild(node, i);
                if (k > node.keys[i]) i++;
            }
            insertNonFull(node.children[i], k);
        }
    }

    private void splitChild(BTreeNode parent, int i) {
        BTreeNode newNode = new BTreeNode(parent.children[i].leaf);
        BTreeNode child = parent.children[i];
        int mid = t - 1;
        newNode.n = t - 1;
        for (int j = 0; j < t - 1; j++) {
            newNode.keys[j] = child.keys[j + t];
        }
        if (!child.leaf) {
            for (int j = 0; j < t; j++) {
                newNode.children[j] = child.children[j + t];
            }
        }
        child.n = t - 1;
        for (int j = parent.n; j > i; j--) {
            parent.children[j + 1] = parent.children[j];
        }
        parent.children[i + 1] = newNode;
        for (int j = parent.n - 1; j >= i; j--) {
            parent.keys[j + 1] = parent.keys[j];
        }
        parent.keys[i] = child.keys[t - 1];
        parent.n++;
    }

    public boolean search(int k) {
        return search(k, root);
    }

    private boolean search(int k, BTreeNode node) {
        int i = 0;
        while (i < node.n && k > node.keys[i]) {
            i++;
        }
        if (i < node.n && k == node.keys[i]) {
            return true;
        }
        if (node.leaf) {
            return false;
        }
        return search(k, node.children[i]);
    }
}

class Main {
    public static void main(String[] args) {
        BTree bt = new BTree(2);
        int[] keys = {10, 20, 30, 40};
        for (int k : keys) {
            bt.insert(k);
        }
        System.out.println("Search 30: " + bt.search(30));
        System.out.println("Search 50: " + bt.search(50));
    }
}
// Output: Search 30: true
// Output: Search 50: false

