BTreeNode* createNode(int leaf) {
    BTreeNode *node = (BTreeNode*)malloc(sizeof(BTreeNode));
    node->keys = (int*)malloc((2 * T - 1) * sizeof(int));
    node->children = (BTreeNode**)malloc(2 * T * sizeof(BTreeNode*));
    node->n = 0;
    node->leaf = leaf;
    return node;
}

BTree* createBTree(int t) {
    BTree *bt = (BTree*)malloc(sizeof(BTree));
    bt->root = createNode(1);
    bt->t = t;
    return bt;
}

void splitChild(BTreeNode *parent, int i, BTreeNode *child) {
    BTreeNode *newNode = createNode(child->leaf);
    int mid = T - 1;
    newNode->n = T - 1;
    for (int j = 0; j < T - 1; j++) {
        newNode->keys[j] = child->keys[j + T];
    }
    if (!child->leaf) {
        for (int j = 0; j < T; j++) {
            newNode->children[j] = child->children[j + T];
        }
    }
    child->n = T - 1;
    for (int j = parent->n; j > i; j--) {
        parent->children[j + 1] = parent->children[j];
    }
    parent->children[i + 1] = newNode;
    for (int j = parent->n - 1; j >= i; j--) {
        parent->keys[j + 1] = parent->keys[j];
    }
    parent->keys[i] = child->keys[T - 1];
    parent->n++;
}

void insertNonFull(BTreeNode *node, int k, int t) {
    int i = node->n - 1;
    if (node->leaf) {
        while (i >= 0 && k < node->keys[i]) {
            node->keys[i + 1] = node->keys[i];
            i--;
        }
        node->keys[i + 1] = k;
        node->n++;
    } else {
        while (i >= 0 && k < node->keys[i]) {
            i--;
        }
        i++;
        if (node->children[i]->n == 2 * t - 1) {
            splitChild(node, i, node->children[i]);
            if (k > node->keys[i]) i++;
        }
        insertNonFull(node->children[i], k, t);
    }
}

void insert(BTree *bt, int k) {
    BTreeNode *root = bt->root;
    if (root->n == 2 * bt->t - 1) {
        BTreeNode *newRoot = createNode(0);
        newRoot->children[0] = root;
        newRoot->n = 0;
        splitChild(newRoot, 0, root);
        bt->root = newRoot;
        insertNonFull(newRoot, k, bt->t);
    } else {
        insertNonFull(root, k, bt->t);
    }
}

int search(BTreeNode *node, int k) {
