    while (i < node->n && k > node->keys[i]) {
        i++;
    }
    if (i < node->n && k == node->keys[i]) {
        return 1;
    }
    if (node->leaf) {
        return 0;
    }
    return search(node->children[i], k);
}

void freeBTreeNode(BTreeNode *node) {
    if (!node->leaf) {
        for (int i = 0; i <= node->n; i++) {
            freeBTreeNode(node->children[i]);
        }
    }
    free(node->keys);
    free(node->children);
    free(node);
}

