class BTreeNode {
public:
    std::vector<int> keys;
    std::vector<BTreeNode*> children;
    bool leaf;

    BTreeNode(bool leaf) : leaf(leaf) {}
};

class BTree {
private:
    BTreeNode* root;
    int t;

public:
    BTree(int t) : t(t) {
        root = new BTreeNode(true);
    }

    void insert(int k) {
        BTreeNode* r = root;
        if (r->keys.size() == 2 * t - 1) {
            BTreeNode* newRoot = new BTreeNode(false);
            newRoot->children.push_back(root);
            splitChild(newRoot, 0);
            root = newRoot;
            insertNonFull(newRoot, k);
        } else {
            insertNonFull(r, k);
        }
    }

    void insertNonFull(BTreeNode* node, int k) {
        int i = node->keys.size() - 1;
        if (node->leaf) {
            node->keys.push_back(0);
            while (i >= 0 && k < node->keys[i]) {
                node->keys[i + 1] = node->keys[i];
                i--;
            }
            node->keys[i + 1] = k;
        } else {
            while (i >= 0 && k < node->keys[i]) {
                i--;
            }
            i++;
            if (node->children[i]->keys.size() == 2 * t - 1) {
                splitChild(node, i);
                if (k > node->keys[i]) i++;
            }
            insertNonFull(node->children[i], k);
        }
    }

    void splitChild(BTreeNode* parent, int i) {
        BTreeNode* newNode = new BTreeNode(parent->children[i]->leaf);
        BTreeNode* child = parent->children[i];
        int mid = t - 1;
        newNode->keys.assign(child->keys.begin() + mid + 1, child->keys.end());
        child->keys.resize(mid);
        parent->keys.insert(parent->keys.begin() + i, child->keys[mid]);
        if (!child->leaf) {
            newNode->children.assign(child->children.begin() + mid + 1, child->children.end());
            child->children.resize(mid + 1);
        }
        parent->children.insert(parent->children.begin() + i + 1, newNode);
    }

    bool search(int k, BTreeNode* node = nullptr) {
        if (!node) node = root;
        int i = 0;
        while (i < node->keys.size() && k > node->keys[i]) {
            i++;
        }
        if (i < node->keys.size() && k == node->keys[i]) {
            return true;
        }
        if (node->leaf) {
            return false;
        }
        return search(k, node->children[i]);
    }

    ~BTree() {
        deleteNode(root);
    }

    void deleteNode(BTreeNode* node) {
        if (!node->leaf) {
            for (BTreeNode* child : node->children) {
                deleteNode(child);
            }
        }
        delete node;
    }
};

