        root = self.root
        if len(root.keys) == 2 * self.t - 1:
            new_root = BTreeNode(False)
            new_root.children.append(self.root)
            self.split_child(new_root, 0)
            self.root = new_root
            self.insert_non_full(new_root, k)
        else:
            self.insert_non_full(root, k)

    def insert_non_full(self, node, k):
        i = len(node.keys) - 1
        if node.leaf:
            node.keys.append(0)
            while i >= 0 and k < node.keys[i]:
                node.keys[i + 1] = node.keys[i]
                i -= 1
            node.keys[i + 1] = k
        else:
            while i >= 0 and k < node.keys[i]:
                i -= 1
            i += 1
            if len(node.children[i].keys) == 2 * self.t - 1:
                self.split_child(node, i)
                if k > node.keys[i]:
                    i += 1
            self.insert_non_full(node.children[i], k)

    def split_child(self, parent, i):
        t = self.t
        new_node = BTreeNode(parent.children[i].leaf)
        mid = t - 1
        new_node.keys = parent.children[i].keys[mid + 1:]
        parent.children[i].keys = parent.children[i].keys[:mid]
        parent.keys.insert(i, parent.children[i].keys[mid])
        if not parent.children[i].leaf:
            new_node.children = parent.children[i].children[mid + 1:]
            parent.children[i].children = parent.children[i].children[:mid + 1]
        parent.children.insert(i + 1, new_node)

