                this.splitChild(node, i);
                if (k > node.keys[i]) i++;
            }
            this.insertNonFull(node.children[i], k);
        }
    }

    splitChild(parent: BTreeNode, i: number): void {
        let t = this.t;
        let newNode = new BTreeNode(parent.children[i].leaf);
