        if (!parent.children[i].leaf) {
            newNode.children = parent.children[i].children.splice(mid + 1);
        }
        parent.children.splice(i + 1, 0, newNode);
    }

    search(k: number, node: BTreeNode = this.root): boolean {
        let i = 0;
        while (i < node.keys.length && k > node.keys[i]) {
            i++;
        }
        if (i < node.keys.length && k === node.keys[i]) {
            return true;
        }
        if (node.leaf) {
            return false;
        }
        return this.search(k, node.children[i]);
    }
}

